export function getOfferById(id: string): OfferData | undefined {
  return offers.find((o) => o.id === id)
}

export function getFeaturedOffers(): OfferData[] {
  return offers.filter((o) => o.featured)
}

export function getOffersByDestinationSlug(slug: string): OfferData[] {
  return offers.filter((o) => o.destination.slug === slug)
}
